// IMPROVEMENT: Validate required environment variables before any processing
const missingVars = [];
if (!$env.STRIPE_SIGNING_SECRET) missingVars.push('STRIPE_SIGNING_SECRET');
if (!$env.SUPABASE_URL) missingVars.push('SUPABASE_URL');
if (!$env.SUPABASE_SERVICE_KEY) missingVars.push('SUPABASE_SERVICE_KEY');
if (missingVars.length > 0) {
  throw new Error('Missing required env vars: ' + missingVars.join(', '));
}
const crypto = require('crypto');
const body = $input.first().json;
const sigHeader = body.headers['stripe-signature'] || '';
const secret = $env.STRIPE_SIGNING_SECRET || '';
if (!sigHeader || !secret) {
  return [{ json: { signatureValid: false, reason: 'Missing signature or secret' } }];
}
try {
  const elements = sigHeader.split(',');
  const tsEl = elements.find(e => e.startsWith('t='));
  const sigEl = elements.find(e => e.startsWith('v1='));
  if (!tsEl || !sigEl) throw new Error('Malformed signature header');
  const timestamp = tsEl.split('=')[1];
  const signature = sigEl.split('=')[1];
  const rawBody = typeof body.body === 'string' ? body.body : JSON.stringify(body.body);
  const expected = crypto.createHmac('sha256', secret).update(timestamp + '.' + rawBody).digest('hex');
  const isValid = crypto.timingSafeEqual(Buffer.from(signature, 'utf8'), Buffer.from(expected, 'utf8'));
  const tolerance = 300;
  const now = Math.floor(Date.now() / 1000);
  const isFresh = Math.abs(now - parseInt(timestamp)) <= tolerance;
  return [{ json: { signatureValid: isValid && isFresh, ...body } }];
} catch (e) {
  return [{ json: { signatureValid: false, reason: e.message, ...body } }];
}

const eventId = $input.first().json.body.id;
const eventType = $input.first().json.body.type || '';
const obj = $input.first().json.body.data?.object || {};
const sbUrl = $env.SUPABASE_URL;
const sbKey = $env.SUPABASE_SERVICE_KEY;
const headers = { 'apikey': sbKey, 'Authorization': 'Bearer ' + sbKey, 'Content-Type': 'application/json' };
let isDuplicate = false;
try {
  // SECURITY: encodeURIComponent() prevents URL injection via eventId
  const check = await this.helpers.httpRequest({ method: 'GET', url: sbUrl + '/rest/v1/payment_events?stripe_event_id=eq.' + encodeURIComponent(eventId) + '&select=id,status', headers: { apikey: sbKey, Authorization: 'Bearer ' + sbKey } });
  if (check && check.length > 0) { isDuplicate = true; }
  else {
    await this.helpers.httpRequest({ method: 'POST', url: sbUrl + '/rest/v1/payment_events', headers, body: { stripe_event_id: eventId, event_type: eventType, status: 'processing', customer_id: obj.customer || '', invoice_id: obj.id || '', subscription_id: obj.subscription || '' } });
  }
} catch (e) { /* If DB fails, still process to avoid losing events */ }
return [{ json: { isDuplicate, ...$input.first().json } }];

const event = $input.first().json.body;
const invoice = event.data.object;
const attemptCount = invoice.attempt_count || 1;
let failureStage, urgencyLevel, nextAction, slackUrgencyEmoji;
if (attemptCount === 1) { failureStage='first_failure'; urgencyLevel='low'; nextAction='friendly_reminder'; slackUrgencyEmoji='🟡'; }
else if (attemptCount === 2) { failureStage='second_failure'; urgencyLevel='medium'; nextAction='update_card_request'; slackUrgencyEmoji='🟠'; }
else if (attemptCount === 3) { failureStage='third_failure'; urgencyLevel='high'; nextAction='urgent_warning'; slackUrgencyEmoji='🔴'; }
else { failureStage='final_failure'; urgencyLevel='critical'; nextAction='cancellation_warning'; slackUrgencyEmoji='💀'; }
const amountDue = (invoice.amount_due || 0) / 100;
const currency = (invoice.currency || 'usd').toUpperCase();
// BUG FIX: Null-safe fallback chain — handles missing customer object gracefully
const customerEmail = invoice.customer_email || invoice.customer?.email || '';
const customerName = invoice.customer_name || (invoice.customer && typeof invoice.customer === 'object' ? invoice.customer.name : null) || (customerEmail ? customerEmail.split('@')[0] : 'Customer');
const customerId = invoice.customer || '';
const subscriptionId = invoice.subscription || '';
const invoiceId = invoice.id || '';
const cardUpdateUrl = $env.STRIPE_PORTAL_URL || 'https://billing.stripe.com/p/login/YOUR_PORTAL_ID';
// IMPROVEMENT: Email validation — flag invalid emails rather than sending to bad addresses
const emailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(customerEmail);
// Failure reason mapping
const codeMap = { card_declined:'Your card was declined by the bank', insufficient_funds:'Insufficient funds on card', expired_card:'Your card has expired', incorrect_cvc:'Incorrect CVC code entered', processing_error:'Temporary processing error' };
let failureReason = 'unknown', failureCode = '';
if (invoice.last_finalization_error) { failureReason = invoice.last_finalization_error.message || 'Payment method declined'; failureCode = invoice.last_finalization_error.code || ''; }
else if (invoice.charge && typeof invoice.charge === 'object') { failureReason = invoice.charge.failure_message || 'Card declined'; failureCode = invoice.charge.failure_code || ''; }
if (failureCode && codeMap[failureCode]) failureReason = codeMap[failureCode];
// Segmentation (Task 8)
let revenueTier = 'low';
if (amountDue >= 100) revenueTier = 'high';
else if (amountDue >= 20) revenueTier = 'mid';
// IMPROVEMENT: Deterministic A/B testing — hash-based, consistent per customer across retries
const templateVariant = parseInt((customerId || '').slice(-1), 16) % 2 === 0 ? 'A' : 'B';
return [{ json: { customerEmail, customerName, customerId, subscriptionId, invoiceId, amountDue, currency, attemptCount, failureStage, urgencyLevel, nextAction, failureReason, failureCode, cardUpdateUrl, invoiceUrl: invoice.hosted_invoice_url || '', eventId: event.id, eventTimestamp: new Date((event.created||0)*1000).toISOString(), processedAt: new Date().toISOString(), revenueTier, templateVariant, emailValid, slackUrgencyEmoji } }];

