  Prefer: 'return=minimal'
};

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: sbUrl + '/rest/v1/churn_events',
    headers: h,
    body: {
      stripe_subscription_id: d.subscriptionId,
      stripe_customer_id: d.customerId,
      customer_email: d.customerEmail,
      customer_name: d.customerName,
      monthly_revenue_lost: d.monthlyRevenueLost,
      currency: d.currency,
      cancel_reason: d.cancelReason,
      revenue_tier: d.revenueTier,
      stripe_event_id: d.eventId,
      cancelled_at: d.cancelledAt
    }
  });
  // SECURITY: encodeURIComponent() prevents URL injection via eventId
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: sbUrl + '/rest/v1/payment_events?stripe_event_id=eq.' + encodeURIComponent(d.eventId),
    headers: h,
    body: { status: 'processed' }
  });
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: sbUrl + '/rest/v1/dunning_events?stripe_event_id=eq.' + encodeURIComponent(d.eventId),
    headers: h,
    body: { failure_stage: d.failureStage || 'final_failure' }
  });
} catch(e) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/failed_integrations',
      headers: { apikey: sbKey, Authorization: 'Bearer ' + sbKey, 'Content-Type': 'application/json', Prefer: 'return=minimal' },
